{
  name: "get_trends",
  description: `Get time-series trend data for pass/fail rates over a period. Useful for tracking test health over time.

Fields returned per day:
- date: ISO date (YYYY-MM-DD)
- executions: number - Runs on this day
- passed: number - Passed tests count
- failed: number - Failed tests count
- pass_rate: number - Daily percentage (0-100)`,
  inputSchema: {
    type: "object" as const,
    properties: {
      days: { type: "number", description: "Number of days to look back", default: 7 },
    },
  },
}

case "get_trends": {
  const input = z.object({ days: z.number().min(1).max(90).default(7) }).parse(args)

  const trends = await db.getTrendData(orgId, input.days)

  return jsonResponse({
    organization: authContext.organizationSlug,
    days: input.days,
    trends,
  })
}

export async function getTrendData(organizationId: number, days = 7, dateRange?: DateRangeFilter) {
  const sql = getSql()
  const conditions = ["completed_at IS NOT NULL", `organization_id = ${organizationId}`]

  if (dateRange?.from) {
    conditions.push(`started_at >= '${dateRange.from}'`)
  } else {
    conditions.push(`started_at > NOW() - INTERVAL '${days} days'`)
  }

  if (dateRange?.to) {
    conditions.push(`started_at <= '${dateRange.to}'`)
  }

  const whereClause = `WHERE ${conditions.join(" AND ")}`

  const result = await sql`
    SELECT
      DATE(started_at) as date,
      COUNT(*) FILTER (WHERE status = 'success') as passed,
      COUNT(*) FILTER (WHERE status = 'failure') as failed,
      COUNT(*) as total
    FROM test_executions
    ${sql.unsafe(whereClause)}
    GROUP BY DATE(started_at)
    ORDER BY date ASC
  `

  return result as TrendData[]
}

solution.updated_db_function:
interface TrendOptions {
  period?: 'hour' | 'day' | 'week' | 'month'
  count?: number          // Number of periods to look back
  from?: string           // Explicit start date (ISO 8601)
  to?: string             // Explicit end date (ISO 8601)
}

export async function getTrendData(
  organizationId: number,
  options: TrendOptions = {}
): Promise<TrendDataPoint[]> {
  const sql = getSql()
  const { period = 'day', count, from, to } = options

  const conditions = [
    "completed_at IS NOT NULL",
    `organization_id = ${organizationId}`
  ]

  // Determine time filtering
  if (from) {
    conditions.push(`started_at >= '${from}'`)
  } else if (count) {
    const interval = period === 'hour' ? 'hours' : 
                     period === 'day' ? 'days' :
                     period === 'week' ? 'weeks' : 'months'
    conditions.push(`started_at > NOW() - INTERVAL '${count} ${interval}'`)
  } else {
    // Default: last 7 of the period type
    const interval = period === 'hour' ? 'hours' : 
                     period === 'day' ? 'days' :
                     period === 'week' ? 'weeks' : 'months'
    conditions.push(`started_at > NOW() - INTERVAL '7 ${interval}'`)
  }

  if (to) {
    conditions.push(`started_at <= '${to}'`)
  }

  const whereClause = `WHERE ${conditions.join(" AND ")}`

  // DATE_TRUNC works for all granularities
  const truncExpr = period === 'hour' ? "DATE_TRUNC('hour', started_at)" :
                    period === 'day' ? "DATE_TRUNC('day', started_at)" :
                    period === 'week' ? "DATE_TRUNC('week', started_at)" :
                    "DATE_TRUNC('month', started_at)"

  const query = `
    SELECT
      ${truncExpr} as period,
      COUNT(*) as executions,
      COUNT(*) FILTER (WHERE status = 'success') as passed,
      COUNT(*) FILTER (WHERE status = 'failure') as failed,
      COUNT(*) FILTER (WHERE status NOT IN ('success', 'failure')) as skipped,
      CASE 
        WHEN COUNT(*) > 0 
        THEN ROUND(COUNT(*) FILTER (WHERE status = 'success')::decimal / COUNT(*) * 100, 1)
        ELSE 0
      END as pass_rate
    FROM test_executions
    ${whereClause}
    GROUP BY ${truncExpr}
    ORDER BY period ASC
  `

  const result = await sql.unsafe(query)
  return result as TrendDataPoint[]
}

solution.updated_tool_definition:
{
  name: "get_trends",
  description: `Get time-series trend data for pass/fail rates. Supports flexible time granularity.

Fields returned per period:
- period: ISO datetime - Period start (hour/day/week/month depending on granularity)
- executions: number - Total runs in this period
- passed: number - Passed execution count
- failed: number - Failed execution count
- skipped: number - Skipped/other execution count
- pass_rate: number - Success percentage (0-100)

Use 'period' param to control granularity. Use 'from'/'to' for custom date ranges.`,
  inputSchema: {
    type: "object" as const,
    properties: {
      period: {
        type: "string",
        enum: ["hour", "day", "week", "month"],
        default: "day",
        description: "Time granularity for aggregation",
      },
      count: {
        type: "number",
        description: "Number of periods to look back (e.g., count=7 with period=day = last 7 days)",
      },
      days: {
        type: "number",
        description: "DEPRECATED: Use count + period instead. Number of days to look back.",
      },
      from: {
        type: "string",
        description: "Start date (ISO 8601). Overrides count/days if specified.",
      },
      to: {
        type: "string",
        description: "End date (ISO 8601). Defaults to now.",
      },
    },
  },
}

solution.updated_handler:
case "get_trends": {
  const input = z.object({
    period: z.enum(["hour", "day", "week", "month"]).default("day"),
    count: z.number().min(1).max(100).optional(),
    days: z.number().min(1).max(90).optional(),      // Deprecated but supported
    from: z.string().optional(),
    to: z.string().optional(),
  }).parse(args)

  // Validate limits per period type
  const maxCounts: Record<string, number> = {
    hour: 168,    // 7 days of hours
    day: 90,      // 90 days
    week: 52,     // 1 year of weeks
    month: 24,    // 2 years of months
  }

  const effectiveCount = input.count || input.days || 7
  const maxForPeriod = maxCounts[input.period]

  if (effectiveCount > maxForPeriod) {
    return errorResponse(
      `count exceeds maximum for ${input.period} period (max: ${maxForPeriod})`
    )
  }

  const trends = await db.getTrendData(orgId, {
    period: input.period,
    count: effectiveCount,
    from: input.from,
    to: input.to,
  })

  return jsonResponse({
    organization: authContext.organizationSlug,
    period: input.period,
    count: trends.length,
    date_range: {
      from: input.from || `${effectiveCount} ${input.period}s ago`,
      to: input.to || "now",
    },
    trends,
  })
}
